import { useRef } from 'react';
import '../styles/About.css';

const timelineData = [
  {
    year: '2022 – Present',
    title: 'Bachelor of Science in Information Technology',
    sub: 'University Name · Davao City',
  },
  {
    year: '2023 – Present',
    title: 'Freelance Web Developer',
    sub: 'Independent Projects & Client Work',
  },
  {
    year: '2024',
    title: 'UI/UX Design Certification',
    sub: 'Online Learning · Figma & Prototyping',
  },
];

export default function About() {
  const frameRef = useRef(null);
  const tearTimeout = useRef(null);

  /* 3D Tilt */
  const handleMouseMove = (e) => {
    const frame = frameRef.current;
    if (!frame) return;
    const rect = frame.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const rotateY = ((x - rect.width / 2) / (rect.width / 2)) * 12;
    const rotateX = ((rect.height / 2 - y) / (rect.height / 2)) * 12;
    frame.style.transform = `perspective(1200px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) translateZ(8px)`;
  };

  const handleMouseLeave = () => {
    const frame = frameRef.current;
    if (!frame) return;
    frame.style.transform = 'perspective(1200px) rotateX(0deg) rotateY(0deg) translateZ(0px)';
  };

  /* Paper tear + shards */
  const createShards = (cx, cy) => {
    for (let i = 0; i < 14; i++) {
      const shard = document.createElement('div');
      shard.className = 'tear-shard';
      const angle = (i / 14) * Math.PI * 2;
      const dist = 50 + Math.random() * 90;
      const tx = Math.cos(angle) * dist * (Math.random() * 0.8 + 0.5);
      const ty = Math.sin(angle) * dist * (Math.random() * 0.8 + 0.5) - 30;
      const rot = (Math.random() - 0.5) * 180;
      shard.style.setProperty('--tx', `${tx}px`);
      shard.style.setProperty('--ty', `${ty}px`);
      shard.style.setProperty('--rot', `${rot}deg`);
      shard.style.left = `${cx}px`;
      shard.style.top = `${cy}px`;
      shard.style.width = `${5 + Math.random() * 14}px`;
      shard.style.height = `${3 + Math.random() * 10}px`;
      document.body.appendChild(shard);
      setTimeout(() => shard.remove(), 800);
    }
  };

  const handleClick = () => {
    const frame = frameRef.current;
    if (!frame || tearTimeout.current) return;
    const rect = frame.getBoundingClientRect();
    createShards(rect.left + rect.width / 2, rect.top + rect.height / 2);

    frame.classList.add('tear-effect', 'click-ripple');
    const img = frame.querySelector('img');
    if (img) { img.style.filter = 'brightness(1.3) contrast(1.2)'; }

    tearTimeout.current = setTimeout(() => {
      frame.classList.remove('tear-effect', 'click-ripple');
      if (img) img.style.filter = '';
      tearTimeout.current = null;
    }, 600);
  };

  return (
    <section id="about" className="about-section">
      <div className="about-layout">

        {/* Photo */}
        <div className="about-visual reveal">
          <div
            className="photo-frame"
            ref={frameRef}
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            onClick={handleClick}
          >
            <div className="photo-placeholder">
              {/* Replace src with your actual photo path */}
              <img src="profile.jpg" alt="Aaron Lazarte" onError={(e) => e.target.style.display = 'none'} />
            </div>
          </div>
        </div>

        {/* Info */}
        <div className="about-info">
          <div className="section-header">
            <div className="section-tag">About Me</div>
            <h2 className="section-title reveal reveal-delay-1">
              Crafting <span className="accent">Digital</span><br />Experiences
            </h2>
          </div>

          <p className="about-bio reveal reveal-delay-2">
            Hi, I'm Aaron Lazarte, an IT student and aspiring software developer. I enjoy building meaningful projects, learning new technologies, and growing my skills every day. Outside of tech, I maintain a healthy lifestyle through running, which teaches me discipline, consistency, and perseverance—values I bring into every project I work on.
          </p>

          <blockquote className="about-mission reveal reveal-delay-3">
            "My mission is to continuously grow as a developer while contributing to projects
            that make a real difference — one clean line of code at a time."
          </blockquote>

          <div className="timeline reveal reveal-delay-3">
            {timelineData.map((item, i) => (
              <div className="timeline-item" key={i}>
                <div className="timeline-dot" />
                <div>
                  <div className="timeline-year">{item.year}</div>
                  <div className="timeline-title">{item.title}</div>
                  <div className="timeline-sub">{item.sub}</div>
                </div>
              </div>
            ))}
          </div>
        </div>

      </div>
    </section>
  );
}
